INSERT INTO "public"."pc_builder_scenarios" ("id", "exam", "title", "badge", "badge_color", "border_color", "requirements", "categories") VALUES ('family', 'core1', 'Budget-Friendly Family Workstation', 'Family', 'text-green-600 dark:text-green-400', 'border-green-500/30', '["Web browsing, word processing, and video conferencing","Light photo viewing and media playback","Low cost — functional over high-performance","Shared by multiple family members","Must run Windows 11"]', '[{"id":"cpu","label":"Processor (CPU)","reason":"An i3 comfortably handles browsing, Office apps, and video calls at a budget price. Higher-tier CPUs add cost with no perceivable benefit for light home tasks.","correct":"i3","options":[{"id":"i3","label":"Intel Core i3-13100","detail":"4 cores · ideal for everyday tasks · budget"},{"id":"i5","label":"Intel Core i5-13400","detail":"Mid-range · slight overkill for basic use"},{"id":"i7","label":"Intel Core i7-14700K","detail":"High-performance · unnecessary cost here"},{"id":"xeon","label":"Intel Xeon W-2400","detail":"Server workstation · expensive · overkill"}]},{"id":"gpu","label":"Graphics (GPU)","reason":"Integrated graphics handles web browsing, video playback, and video conferencing without issue. A discrete GPU adds $300+ in unnecessary cost that directly conflicts with the budget requirement.","correct":"igpu","options":[{"id":"igpu","label":"Integrated Graphics (Intel UHD)","detail":"Free with CPU · handles all non-gaming tasks"},{"id":"dgpu","label":"Discrete GPU (RTX 3060)","detail":"Adds $300+ · unnecessary for this use case"}]},{"id":"ram","label":"Memory (RAM)","reason":"8 GB DDR4 is comfortable for browsing, Office, and video calls running simultaneously. DDR4 reduces cost vs DDR5. 4 GB is tight with Windows 11 overhead; 16+ GB is wasteful here.","correct":"8ddr4","options":[{"id":"4ddr4","label":"4 GB DDR4","detail":"Tight with Windows 11 · may lag during multitasking"},{"id":"8ddr4","label":"8 GB DDR4","detail":"Comfortable for everyday tasks · cost-effective"},{"id":"16ddr5","label":"16 GB DDR5","detail":"More than needed · higher cost"},{"id":"32ddr5","label":"32 GB DDR5","detail":"Overkill · significant unnecessary expense"}]},{"id":"storage","label":"Primary Storage","reason":"A 500 GB SATA SSD provides fast Windows 11 boot and file access at a budget price. An HDD is too slow; NVMe adds unnecessary cost; 256 GB is tight for a shared family machine.","correct":"500ssd","options":[{"id":"500hdd","label":"500 GB HDD","detail":"Very cheap · slow boot and response times"},{"id":"256ssd","label":"256 GB SATA SSD","detail":"Fast · too small for shared family storage"},{"id":"500ssd","label":"500 GB SATA SSD","detail":"Fast boot · adequate space · budget sweet spot"},{"id":"1tnvme","label":"1 TB NVMe SSD","detail":"Fast · overkill · unnecessary extra cost"}]},{"id":"sound","label":"Audio","reason":"Onboard audio handles video calls, music, and media playback without issue. A dedicated sound card is unnecessary expense that goes against the budget requirement.","correct":"onboard","options":[{"id":"onboard","label":"Onboard Audio (Realtek)","detail":"Built-in · sufficient for calls and media"},{"id":"71card","label":"Dedicated 7.1 Sound Card","detail":"Unnecessary · adds cost with no benefit here"}]},{"id":"peripheral","label":"Communication / Peripherals","reason":"A headset combines microphone and speakers in one device — ideal for video conferencing (Teams/Zoom). A webcam alone lacks audio input; a standalone mic lacks video.","correct":"headset","options":[{"id":"webcam","label":"Webcam only","detail":"Video only · no microphone · incomplete for calls"},{"id":"headset","label":"Headset with Mic","detail":"All-in-one · perfect for video conferencing"},{"id":"extmic","label":"Standalone USB Mic","detail":"Audio only · no video · partial solution"}]}]'), ('gaming', 'core1', 'High-Performance Gaming Workstation', 'Gaming', 'text-purple-600 dark:text-purple-400', 'border-purple-500/30', '["Exceptional frame rates in AAA games","Rapid load times (under 10 seconds)","Ample storage for large game libraries (100 GB+ per title)","Superior audio for immersive and competitive play","Cost is not a constraint","Must run Windows 11"]', '[{"id":"cpu","label":"Processor (CPU)","reason":"A flagship CPU (i9) handles game engines, physics, AI, and streaming simultaneously without bottlenecking a high-end GPU. The i3 would throttle the GPU; Xeon is server-optimized and lacks iGPU.","correct":"i9","options":[{"id":"i3","label":"Intel Core i3-13100","detail":"4 cores · budget office tasks"},{"id":"i7","label":"Intel Core i7-14700K","detail":"20 cores · high-end gaming"},{"id":"i9","label":"Intel Core i9-14900K","detail":"24 cores · flagship gaming & streaming"},{"id":"xeon","label":"Intel Xeon W-2400","detail":"Server · ECC · no integrated graphics"}]},{"id":"gpu","label":"Graphics (GPU)","reason":"Discrete GPUs have dedicated VRAM and thousands of shaders required for modern 3D rendering and ray tracing. Integrated graphics share system RAM and cannot sustain high frame rates in AAA titles.","correct":"dgpu","options":[{"id":"igpu","label":"Integrated Graphics (Intel UHD)","detail":"Shares RAM · suitable for 2D and video"},{"id":"dgpu","label":"NVIDIA RTX 4080 Super","detail":"16 GB VRAM · ray tracing · high-FPS gaming"}]},{"id":"ram","label":"Memory (RAM)","reason":"Modern AAA games recommend 16 GB minimum; 32 GB leaves headroom for streaming software, background apps, and future titles. DDR5 provides higher bandwidth for the CPU and GPU workloads.","correct":"32ddr5","options":[{"id":"8ddr4","label":"8 GB DDR4","detail":"Tight for modern games + OS overhead"},{"id":"16ddr5","label":"16 GB DDR5","detail":"Recommended baseline for gaming"},{"id":"32ddr5","label":"32 GB DDR5","detail":"Optimal · headroom for streaming & future titles"},{"id":"16ecc","label":"16 GB DDR5 ECC","detail":"Server error-correction · no gaming benefit"}]},{"id":"storage","label":"Primary Storage","reason":"NVMe SSDs cut game load times to seconds vs HDDs. 2 TB accommodates multiple large titles (some exceed 150 GB). 256 GB fills up with 1–2 games; HDDs are too slow.","correct":"2tnvme","options":[{"id":"500hdd","label":"500 GB HDD","detail":"~120 MB/s · cheap · slow load times"},{"id":"256ssd","label":"256 GB SATA SSD","detail":"Fast · too small for game libraries"},{"id":"1tnvme","label":"1 TB NVMe SSD","detail":"Fast · fits ~8–10 large games"},{"id":"2tnvme","label":"2 TB NVMe SSD","detail":"Fast · ample space · best for gaming"}]},{"id":"sound","label":"Audio","reason":"A dedicated 7.1 surround sound card provides multi-channel positional audio — critical for competitive gaming (hearing enemy footsteps from direction) and immersive single-player experiences. Onboard audio lacks this fidelity.","correct":"71card","options":[{"id":"onboard","label":"Onboard Audio (Realtek)","detail":"Built-in · adequate for calls and casual media"},{"id":"71card","label":"Dedicated 7.1 Sound Card","detail":"Multi-channel · positional audio · low latency"}]},{"id":"peripheral","label":"Communication / Peripherals","reason":"Streamers and competitive gamers need a dedicated external microphone for clear voice quality during streams and team communication. A headset mic is secondary; standalone condenser mics provide superior audio fidelity.","correct":"extmic","options":[{"id":"webcam","label":"Webcam only","detail":"Video input only · no microphone"},{"id":"headset","label":"Gaming Headset","detail":"Convenient · integrated mic · good all-rounder"},{"id":"extmic","label":"Standalone USB Mic","detail":"Superior clarity · ideal for streaming & comms"}]}]'), ('corp-laptop', 'core2', 'Corporate Laptop — Security Hardening', 'Enterprise', 'text-blue-600 dark:text-blue-400', 'border-blue-500/30', '["Must protect data if laptop is lost or stolen","Remote employees need secure access to company resources","Strong login authentication required beyond just a password","Must meet company compliance requirements","Windows 11 — users are standard (non-admin) accounts"]', '[{"id":"encryption","label":"Full-Disk Encryption","reason":"BitLocker (Windows Pro/Enterprise) encrypts the entire drive using AES and ties to the TPM chip. If the drive is removed and placed in another machine, data is unreadable without the recovery key. EFS only encrypts individual files and doesn''t protect the full OS volume.","correct":"bitlocker","options":[{"id":"none","label":"No encryption","detail":"Data readable if drive removed"},{"id":"efs","label":"EFS (Encrypting File System)","detail":"Per-file/folder · tied to user account"},{"id":"bitlocker","label":"BitLocker","detail":"Full-volume · AES · TPM-backed · laptop protection"},{"id":"veracrypt","label":"VeraCrypt (3rd party)","detail":"Open-source · cross-platform · not MDM-managed"}]},{"id":"authentication","label":"Login Authentication","reason":"MFA (password + authenticator app or smart card) ensures that a stolen password alone cannot grant access. A PIN alone is a single factor. Biometrics alone can be spoofed in low-security implementations. Combining factors dramatically reduces unauthorized access risk.","correct":"mfa","options":[{"id":"pin","label":"PIN only","detail":"Single factor · convenient · not strong enough"},{"id":"pass","label":"Complex password only","detail":"Single factor · can be stolen via phishing"},{"id":"bio","label":"Biometric (fingerprint) only","detail":"Single factor · convenient but can fail"},{"id":"mfa","label":"MFA (password + authenticator)","detail":"Two factors · highly resistant to compromise"}]},{"id":"remote-access","label":"Remote Network Access","reason":"A VPN creates an encrypted tunnel between the remote laptop and corporate network, protecting data in transit over public internet. RDP without VPN exposes RDP port 3389 to the internet — a major attack surface. Direct internet access bypasses corporate security controls.","correct":"vpn","options":[{"id":"direct","label":"Direct internet connection","detail":"No encryption · corporate resources exposed"},{"id":"rdp","label":"RDP directly to office PC","detail":"Port 3389 exposed · brute-force risk"},{"id":"vpn","label":"Always-on VPN (IPSec/SSL)","detail":"Encrypted tunnel · all traffic secured"},{"id":"proxy","label":"Web proxy only","detail":"Filters HTTP/S only · not full network access"}]},{"id":"endpoint-security","label":"Endpoint Protection","reason":"EDR (Endpoint Detection and Response) goes beyond traditional antivirus — it monitors behavior, detects zero-day threats, and enables incident response. Traditional signature-based AV only catches known malware. Microsoft Defender Antivirus is the baseline; an enterprise EDR adds behavioral analysis.","correct":"edr","options":[{"id":"none","label":"No antivirus","detail":"Zero protection · never acceptable"},{"id":"free-av","label":"Free consumer antivirus","detail":"Signature-based · no enterprise management"},{"id":"defender","label":"Microsoft Defender Antivirus","detail":"Built-in · adequate baseline · signature-based"},{"id":"edr","label":"Enterprise EDR solution","detail":"Behavioral detection · incident response · centrally managed"}]},{"id":"windows-edition","label":"Windows Edition","reason":"Windows Pro (or Enterprise) is required for domain join, Group Policy enforcement, BitLocker, and Remote Desktop. Windows Home lacks these enterprise features. Windows Enterprise adds additional controls but is typically licensed separately through volume licensing.","correct":"pro","options":[{"id":"home","label":"Windows 11 Home","detail":"No BitLocker · no domain join · no Group Policy"},{"id":"pro","label":"Windows 11 Pro","detail":"BitLocker · domain join · Group Policy · RDP"},{"id":"enterprise","label":"Windows 11 Enterprise","detail":"All Pro features + AppLocker · DirectAccess · volume licensing"},{"id":"edu","label":"Windows 11 Education","detail":"Similar to Enterprise · academic licensing only"}]}]'), ('malware-response', 'core2', 'Malware Incident Response Workstation', 'Incident Response', 'text-red-600 dark:text-red-400', 'border-red-500/30', '["User reports browser redirects and pop-up ads appearing constantly","Antivirus has been disabled and won''t re-enable","New toolbar appeared in browser without user installing it","System is very slow; unknown processes visible in Task Manager","User needs the system back ASAP with data preserved"]', '[{"id":"first-step","label":"First Response Action","reason":"Immediately isolating the infected machine from the network prevents malware from spreading to other systems, communicating with its C2 server, or exfiltrating data. This is always the first step — before scanning or attempting repair. Disconnect ethernet and disable Wi-Fi.","correct":"isolate","options":[{"id":"scan-online","label":"Run antivirus scan immediately","detail":"AV may be disabled · network still connected"},{"id":"isolate","label":"Disconnect from network (isolate)","detail":"FIRST STEP — stops spread and C2 communication"},{"id":"reboot","label":"Reboot the system","detail":"May re-run malware at startup"},{"id":"backup-now","label":"Backup files immediately","detail":"May copy infected files to backup"}]},{"id":"scan-method","label":"Malware Scanning Approach","reason":"Scanning offline (booting from external media or using Windows PE) bypasses rootkits and malware that hook into the running OS to hide themselves. In-OS scans miss malware that disables AV or hides from the running OS. Safe Mode partially helps but is not as thorough as fully offline scanning.","correct":"offline-scan","options":[{"id":"in-os","label":"Normal Windows scan","detail":"Rootkits can hide from scans within running OS"},{"id":"safe-mode","label":"Safe Mode scan","detail":"Better · minimal drivers · but OS still running"},{"id":"offline-scan","label":"Bootable offline scanner (outside OS)","detail":"BEST — malware cannot hide from external scanner"},{"id":"online-scan","label":"Web-based online scan","detail":"Requires internet · limited to browser analysis"}]},{"id":"system-restore","label":"System Restore Before Scanning","reason":"System Restore must be disabled before removing malware because restore points may contain copies of the malware. If you remove malware but leave infected restore points, the user could inadvertently restore the malware. After cleaning is complete, re-enable System Restore and create a new clean restore point.","correct":"disable-sr","options":[{"id":"leave-sr","label":"Leave System Restore enabled","detail":"Malware copies survive in restore points"},{"id":"disable-sr","label":"Disable System Restore before cleaning","detail":"CORRECT — prevents restoring malware from restore points"},{"id":"restore-now","label":"Restore to previous point immediately","detail":"May restore malware that was already present"},{"id":"delete-all","label":"Delete all restore points first","detail":"Same as disabling · but disable is the standard step"}]},{"id":"post-removal","label":"After Malware Removal","reason":"After removal: re-enable System Restore and create a fresh restore point, apply all OS and application patches to close exploited vulnerabilities, update antivirus definitions, schedule regular scans, and monitor for recurrence. Simply removing malware without patching leaves the same vulnerability for re-infection.","correct":"patch-monitor","options":[{"id":"done","label":"Declare clean — no further steps","detail":"Vulnerability still open · re-infection likely"},{"id":"patch-monitor","label":"Patch OS, update AV, re-enable SR, monitor","detail":"CORRECT — closes vulnerability and prevents recurrence"},{"id":"reinstall-os","label":"Reinstall OS immediately","detail":"Nuclear option · data loss risk · not always necessary"},{"id":"just-av","label":"Only update antivirus definitions","detail":"Partial — OS patches and monitoring still needed"}]}]'), ('soho-security', 'core2', 'SOHO Network — Wireless Security Setup', 'SOHO', 'text-green-600 dark:text-green-400', 'border-green-500/30', '["Small office with 10 employees plus occasional visitors","Protect business data from unauthorized access","Employees should not access each other''s devices","Visitors should have internet access but not see business resources","Prevent unauthorized devices from joining the network"]', '[{"id":"wifi-security","label":"Wireless Security Protocol","reason":"WPA3 is the current recommended standard using SAE (Simultaneous Authentication of Equals) instead of PSK, protecting against offline dictionary attacks. WPA2-AES is also acceptable if WPA3 is unavailable. WEP and WPA are broken and must never be used. Open networks have no encryption.","correct":"wpa3","options":[{"id":"open","label":"Open (no security)","detail":"No password · all traffic visible · never use"},{"id":"wep","label":"WEP","detail":"Broken · crackable in minutes · never use"},{"id":"wpa2","label":"WPA2-AES (CCMP)","detail":"Strong · widely supported · still acceptable"},{"id":"wpa3","label":"WPA3","detail":"Current best · SAE · forward secrecy · use this"}]},{"id":"guest-network","label":"Visitor Internet Access","reason":"A guest VLAN/network isolates visitor traffic from the business LAN. Guests get internet access but cannot see or reach internal servers, printers, or employee devices. Sharing the business Wi-Fi password gives visitors full LAN access. A separate hotspot is an option but adds cost and complexity.","correct":"guest-vlan","options":[{"id":"share-pass","label":"Share main Wi-Fi password","detail":"Visitors on same LAN as business — risky"},{"id":"no-access","label":"No internet for visitors","detail":"Inconvenient · poor customer experience"},{"id":"guest-vlan","label":"Separate guest VLAN/network","detail":"Isolated · internet only · best practice"},{"id":"hotspot","label":"Completely separate · extra cost"}]},{"id":"mac-filtering","label":"Device Access Control","reason":"MAC filtering alone is weak (MAC addresses can be spoofed) but adds a layer of difficulty for casual attackers. Combined with a strong WPA3 passphrase, it is a reasonable SOHO control. 802.1X (RADIUS) is the enterprise standard but complex to set up in a SOHO environment.","correct":"mac-filter-plus","options":[{"id":"none","label":"No additional controls","detail":"Password only · any device with password joins"},{"id":"mac-filter-plus","label":"MAC filtering + strong WPA3","detail":"Layered defense · reasonable for SOHO"},{"id":"radius","label":"802.1X / RADIUS authentication","detail":"Enterprise-grade · per-user certs · complex for SOHO"},{"id":"hide-ssid","label":"Hidden SSID only","detail":"Security through obscurity · easily defeated"}]},{"id":"router-hardening","label":"Router Administration Security","reason":"Default router credentials (admin/admin or admin/password) are published online and exploited within minutes of connection. Disabling WPS prevents PIN brute-force attacks. Disabling remote management prevents external attackers from accessing the admin interface. Firmware updates patch known vulnerabilities.","correct":"hardened","options":[{"id":"default","label":"Keep default settings","detail":"Default creds + WPS enabled · immediately exploitable"},{"id":"just-pass","label":"Change admin password only","detail":"Partial improvement · WPS still vulnerable"},{"id":"hardened","label":"Change creds, disable WPS, update firmware","detail":"Full hardening · best practice"},{"id":"remote","label":"Enable remote management for convenience","detail":"Exposes admin to internet — avoid"}]}]'), ('windows-deploy', 'core2', 'Windows Deployment Scenario', 'OS Setup', 'text-purple-600 dark:text-purple-400', 'border-purple-500/30', '["Deploy Windows 11 to 50 new corporate laptops","Each laptop must join the company Active Directory domain","Standard corporate applications pre-installed","BitLocker must be enabled on all drives","Time-efficient — avoid manual setup on each machine"]', '[{"id":"deploy-method","label":"Deployment Method","reason":"PXE (Preboot Execution Environment) with WDS (Windows Deployment Services) allows mass deployment over the network — machines boot from the network and receive an automated OS image. USB/DVD requires physical media per machine. Manual install is impractical at scale. MDM (Autopilot) is modern but requires Azure AD.","correct":"pxe-wds","options":[{"id":"manual","label":"Manual install on each laptop","detail":"Time-consuming · 50 laptops · impractical"},{"id":"usb","label":"Bootable USB drive per machine","detail":"Faster than manual · still requires hands-on each machine"},{"id":"pxe-wds","label":"PXE boot + WDS network deployment","detail":"Network image push · scalable · automated · best choice"},{"id":"autopilot","label":"Windows Autopilot (Azure AD)","detail":"Modern · cloud-based · requires Azure licensing"}]},{"id":"partition","label":"Disk Partition Style","reason":"GPT (GUID Partition Table) with UEFI is required for Windows 11 and supports drives larger than 2 TB. MBR with BIOS is limited to 2 TB and 4 primary partitions — a legacy standard. Windows 11 requires UEFI and Secure Boot, which requires GPT. GPT also supports more partitions and is more resilient.","correct":"gpt-uefi","options":[{"id":"mbr-bios","label":"MBR + Legacy BIOS","detail":"Legacy · 2 TB limit · 4 partitions · no Secure Boot"},{"id":"mbr-uefi","label":"MBR + UEFI","detail":"Partial · UEFI without Secure Boot benefits"},{"id":"gpt-uefi","label":"GPT + UEFI","detail":"Required for Windows 11 · Secure Boot · modern standard"},{"id":"dynamic","label":"Dynamic disk","detail":"Flexible volumes but not needed for boot drives"}]},{"id":"file-system","label":"File System for System Drive","reason":"NTFS is required for a Windows system drive. It supports permissions, encryption (EFS), journaling, large files, and is required for BitLocker. FAT32 has a 4 GB file size limit and no security features. exFAT is designed for removable drives. ReFS is a newer Microsoft file system for storage pools but not for OS boot drives.","correct":"ntfs","options":[{"id":"fat32","label":"FAT32","detail":"4 GB file limit · no permissions · for USB drives"},{"id":"exfat","label":"exFAT","detail":"For flash drives · no permissions or journaling"},{"id":"ntfs","label":"NTFS","detail":"Required for Windows · permissions · BitLocker · journaling"},{"id":"refs","label":"ReFS","detail":"Modern resilient FS · for storage pools · not for OS boot"}]},{"id":"activation","label":"Windows Activation Method","reason":"KMS (Key Management Service) is the standard volume activation method for enterprise deployments. A local KMS server activates all corporate machines without each needing individual product keys or internet access. Retail keys are for individual consumer purchases. MAK (Multiple Activation Key) is a one-time volume key but doesn''t auto-renew. Windows Autopilot handles modern cloud activation.","correct":"kms","options":[{"id":"retail","label":"Individual retail product key each","detail":"50 separate keys · unmanageable at scale"},{"id":"kms","label":"KMS (Key Management Service)","detail":"Corporate volume activation · automatic · scalable"},{"id":"mak","label":"MAK (Multiple Activation Key)","detail":"Volume key · fixed activations · no auto-renewal"},{"id":"no-activate","label":"Skip activation","detail":"Watermark · restricted features · non-compliant"}]}]');